mapper.select:
SELECT id, execution_id, job_order, job_type, job_name, job_id, status, log, started_at, completed_at
FROM pipeline_job_execution
WHERE execution_id = #{executionId} AND job_order = #{jobOrder}

mapper.update:
UPDATE pipeline_job_execution
SET status = #{newStatus},
    log = #{log},
    completed_at = #{completedAt}
WHERE id = #{id}
  AND status = #{expectedStatus}
